from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetShotsNode(BaseNode):
    name = "Prism: Get Shots"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_output("sequences", "list")
        self.add_output("shots", "list")
        self.add_output("shot_count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'sequences': [], 'shots': [], 'shot_count': 0}
        try:
            sequences, shots = core.entities.getShots()
            sequences = list(sequences or [])
            shots = list(shots or [])
            self.log_info(f"Found {len(sequences)} sequence(s), {len(shots)} shot(s).")
            return {'sequences': sequences, 'shots': shots, 'shot_count': len(shots)}
        except Exception as e:
            self.log_error(f"getShots failed: {e}")
            return {'sequences': [], 'shots': [], 'shot_count': 0}

def register_node():
    return PrismGetShotsNode
